prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "6e8e145a4f51488c81c0c89e863a27fa" .
  OPTIONAL { ?model bbo:name ?modelName . }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?path WHERE {
  BIND(<https://www.teamingai-project.eu/kg/process/qualityInspection/sid-E4C327C5-07CC-4A04-9106-8212468451FB> AS ?start)
  BIND(<https://www.teamingai-project.eu/kg/process/qualityInspection/sid-4BB8EBFD-FE07-4324-8F91-9D5FDC116C98> AS ?end)
  {
    ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?end .
    BIND("Direct/Indirect Path Exists" AS ?path)
  }
  UNION
  {
    FILTER NOT EXISTS { ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?end . }
    BIND("No Path Exists" AS ?path)
  }
}
